import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const R=JSON.parse('{"title":"CHAIN REVOLVER","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/CHAIN REVOLVER.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/CHAIN REVOLVER.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/CHAIN REVOLVER.md"};function s(d,b,l,i,V,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"chain-revolver",tabindex:"-1"},[t("CHAIN REVOLVER "),r("a",{class:"header-anchor",href:"#chain-revolver","aria-label":'Permalink to "CHAIN REVOLVER"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),n('<h1 id="chain-revolver-1" tabindex="-1">CHAIN REVOLVER <a class="header-anchor" href="#chain-revolver-1" aria-label="Permalink to &quot;CHAIN REVOLVER&quot;">​</a></h1><p>CHAIN REVOLVER<br> 价格：D+500/C+1000/B+2000（逐级购买）<br> 分类：双枪<br> 描述：二铳白色的双枪，似乎是以模仿特定武器而制造，由于一些特殊原因而与参考原型相差甚远，但作为武器而言性能依旧十分优秀。<br> 【提升至B级时】：二铳白色的双枪，模仿事象兵器-魔铳·ベルヴェルク（贝伯克）而制造的原型武器，可以对于远离自身的空间发动各种各样的攻击。</p><p>特殊的是，使用该武器进行攻击时，每造成1点多次攻击减值，就可以将最终造成的伤害，拆成两次伤害平均计算，同时作用于目标身上，只需要正常计算一次伤害减免与其他效果的作用（例如多次触发易伤、异常点数等）。（如最终造成4点伤害，1点多次攻击减值，就可以将伤害/2计算一次的，即4/2=2，将4点伤害改为2+2点伤害，2点攻击减值就是4/2/2=1，将4点伤害改为1+1+1+1点伤害等等。）</p><p>你可以选择在购买后再支付D+500分对武器改装。<br> 使用改装后的武器进行攻击时，若计算对方破防后，本次攻击仍具有破防效果，则最多可以将自身【传奇敏捷*10】点剩余的任意破防效果转换为攻击检定上的器械加值，但必须是该武器和下属技艺提供的破防效果。<br> ——<br> 此外，在购买本改装后，武器提供的威猛2将提升至5点。</p><p>D级<br> 武器基本属性：武器伤害7L<br> 武器特殊属性：【高速5】【攻击距离不超过15米内的单位时获得2威猛】【无限子弹】<br> 弹容量：11+1<br> 基础射程：40米<br> 武器体积：4<br> 速射等级：长点射<br> 伤害类型：物理-穿刺<br> 【该武器使用【双枪】专业，表现为两把银白色大型手枪，枪身末端蔓延出锁链紧紧缠绕着使用者的手臂，可以正常享受需要霰弹枪为前提使用的专长/能力。】<br> 【该武器需要使用一个迅捷动作具现化，或使用一个迅捷动作将其遣散，同时附赠10立方米储物空间用于存放使用者的个人物品（无法储存活物）。】</p><p>C级：<br> 武器基本属性：武器伤害15L<br> 武器特殊属性：【高速5】【攻击距离不超过15米内的单位时获得2威猛】【无限子弹】<br> 弹容量：11+1<br> 基础射程：40米<br> 武器体积：4<br> 速射等级：长点射<br> 伤害类型：物理-穿刺<br> 【保留上一等级的效果。此外，持有者可以自由动作声明，在一场景内将该武器的任意点武器伤害转为在格挡时生效的闪避防御。】<br> 【该武器进行格挡使用技能-射击+专业-双枪，而不是武技与下属相关专业。】</p><p>B级<br> 武器基本属性：武器伤害22L<br> 武器特殊属性：【高速5】【攻击距离不超过15米内的单位时获得2威猛】【无限子弹】【幻灭】<br> 弹容量：11+1<br> 基础射程：40米<br> 武器体积：4<br> 速射等级：长点射<br> 伤害类型：物理-穿刺<br> 【保留之前等级的效果。此外，使用该武器进行的攻击具有B级时空来源的传送攻击。】 【攻击命中后，其需要进行一次反射豁免，失败则会在原地留下灵魂碎片以供攻击，这是一个B级别、创伤来源的魂牵效果】<br> 【每轮一次，若你对攻击出目不满意，则可以进行一次重骰，必须接受重骰后的结果。】</p><p>【CHAIN REVOLVER下属技能树】<br> 普攻-双枪连射<br> 价格：D+500<br> 分类：被动<br> 描述：分别持有两把铳枪，依次进行左+右+左枪连发+右枪重的改良普通攻击，在清空弹仓后将两把枪向两侧下倾退出弹壳（快速装填）。<br> 效果：<br> 该武器的速射等级提升至【连射】，该武器具有的【高速5】提升至【高速8】。这是由于使用者的攻击繁多，使敌人应接不暇所带来的高速，因此还会如同进行了2次攻击一样计算，额外攻击只会造成额外的多次攻击减值。<br> 升级（D+500）：该武器基础射程+1倍，同时免疫不超过C级【潮湿】带来的影响。<br> 升级（C+1000）：该武器获得【超级贯穿】特性，若具有【破甲】，则使【破甲】数值增加2点。</p><p>貳式-击铁冲击<br> 价格：C+1500<br> 分类：被动<br> 描述：更具有杀伤力的射击，附带喷射能量造成范围伤害。<br> 效果：你在攻击时可以选择同时攻击面前扇形范围内的所有敌人，范围等同该武器射程。<br> 若应用了这一效果，则使本次攻击可以不进行正常防御流程，而是改为目标使用反射豁免。本次攻击额外附带【高速5】，同时伤害类型转为纯能量伤害。<br> 【购买这一能力不会获得自由属性。】</p><p>拾叁式-左轮爆破<br> 前提：貳式-击铁冲击<br> 价格：C+1250<br> 分类：被动<br> 描述：腾空同时使用双枪射击，在表现上是逆旋身体跳跃，双枪散射四周，最后灵巧落地。<br> 效果：【貳式-击铁冲击】效果中提到的范围改为-以自身为中心半径等同武器射程的圆形范围。此外，使用该武器进行的攻击，将增加5点高速，以及【余波】特性。</p><p>肆式-制地爆破<br> 价格：D+500/C+1000（分别购买）<br> 分类：被动<br> 描述：跳跃到空中超下方发射炸裂弹，可以连续发射，有很长的滞空时间。<br> 效果：<br> 【D级】你现在可以准确的控制跳跃的落点和距离而无需检定，同时能够将跳跃和移动结合起来，但每次跳跃的高度不能超过移动距离的1/2，回合结束时仍然需要站在稳固的落脚点上，否则就会坠落。<br> 此外，你在进行的攻击中将附带1点额外的伤害，伤害类型等同攻击造成的伤害。</p><p>【C级】你具有【滞空】，这一效果可以在你进行跳跃，或坠落时使用，随时可以消费一个自由动作将自身固定在空中（无法在空中进行移动），但对于【击飞】类效果无效，依旧会正常坠落。解除【滞空】是一个移动动作。<br> 此外，你在进行的攻击中将附带3点额外的伤害，伤害类型等同攻击造成的伤害。</p><p>陸式-闪光海德尔<br> 价格：C+1000<br> 分类：攻击技<br> 动作：标准动作<br> 消耗：无<br> 射程：接触距离<br> 描述：三段式枪斗术，分别是-踢击，铁山靠击倒，近距离枪击（可连射），可以造成强力体术攻击伤害。<br> 效果：<br> 你进行一次普通枪械攻击检定，本次攻击获得4个攻击附加成功，附带一次【绊摔】，以攻击出目为绊摔成功数，对方需要进行正常对抗流程检定，失败则被你击倒，进入【伏地】状态，【摔绊】每轮只会发生一次。<br> 你无视对方因该【伏地】状态提供的对远程攻击的掩蔽防御，因此进入【伏地】状态的单位会在基础防御/闪避防御/洞察防御中合计减少2点，这2点防御减少会因免疫多次攻击减值而被免疫。</p><p>升级（B+2000）：叁式-弹弓脚<br> 描述：强化上段踢击，进行大幅度上撩腿，可以造成硬直。<br> 效果：<br> 将【陸式-闪光海德尔】的效果改为：你进行一次普通枪械攻击检定，一次【摔绊】，然后再进行一次普通枪械攻击检定。<br> 第一次攻击出目为绊摔成功数，对方需要进行正常对抗流程检定，失败则被你击倒，进入【伏地】状态，【摔绊】每轮只会发生一次，正常造成一次多次攻击减值。<br> ——<br> 普通枪械攻击-摔绊-普通枪械攻击，这三次检定中，你可以任选2次附带【定身】效果，目标以强韧检定豁免，目标为你的伤害出目（若选择摔绊，则摔绊也需要减少防御后计算），失败则目标立刻进入【定身】状态，这是一个B级创伤来源的效果。</p><p>冲刺-圆舞<br> 前提：貳式-击铁冲击<br> 价格：C+1000<br> 分类：攻击技<br> 动作：整轮动作<br> 消耗：2点意志力<br> 射程：见下<br> 描述：前冲并旋转射击，可以向四周倾斜火力。<br> 效果：你进行一次普通枪械攻击，本次攻击获得等同自身敏捷*1点技艺加值，同时如同近战冲锋攻击一样计算，正常获得加值与减值。<br> 这次冲锋有效距离取最大值计算，同时攻击冲锋路径上的所有单位，在冲锋的移动行为结束后，即使对方离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击。</p><p>升级（B+2000）：拾陸式-起爆栓<br> 描述：在冲刺时为敌人打上标记，引爆标记可以击破防御和霸体。<br> 效果：等同于之前等级的效果，但可以额外进行一次相同的攻击，同时这两次攻击将具有B级【接触攻击】特性。</p><p>零枪-狼牙/闪弹雨<br> 价格：C+1000<br> 分类：被动<br> 描述：持续射出光弹，具有【向前方丢出旋转射击的枪轮，返回时可以摁普攻再次丢出】与【发射火箭弹】【发射榴弹】【俯冲爆破】【冲锋时抛散手雷进行爆破】的多种派生效果。<br> 效果：<br> 根据具有的不同能力，将获得不同的效果，但在购买时只能选择针对一种能力生效：【普攻-双枪连射】【陸式-闪光海德尔】【肆式-制地爆破】【冲刺-圆舞】。</p><p>【普攻-双枪连射】<br> 描述：穿插在连射之中的是榴弹与火箭弹，具有强力的杀伤性能。<br> 效果：你进行攻击时，该武器伤害提升你的传奇力量*3L。</p><p>【陸式-闪光海德尔】<br> 描述：在体术攻击中抛掷旋转射击的枪轮，枪轮会一边旋转痛殴敌人，一边连续发射光弹清扫周边敌人。<br> 效果：本次攻击范围改为对于自身为中心，圆形范围内的所有单位生效，射程从触及距离提升至武器射程。</p><p>【肆式-制地爆破】<br> 描述：解除浮空限制，向下伏冲进行爆破攻击。<br> 效果：现在你解除【滞空】无需移动动作，同时可以在空中进行冲刺移动和跳跃，如同完美机动性的飞行一样计算。此外，若你不具有范围攻击能力，则可以减少【肆式-制地爆破】的1点追加伤害，改为对攻击落点造成5米的范围攻击，而非单体攻击。若已具有，则增加1点追加伤害。</p><p>【冲刺-圆舞】<br> 描述：冲锋时抛散手雷进行爆破，在造成伤害的同时掩护自己。<br> 效果：你进行冲锋后，获得等同【冲刺-圆舞】中提供技艺加值数量的掩蔽防御，但该效果提供的掩蔽防御只会持续到你在下回合行动结束时。<br> 【选择这一效果需要额外支付1000分。】</p><p>零枪-神骏<br> 价格：A+4000<br> 前置：貳式-击铁冲击<br> 类型：攻击技<br> 动作：见下<br> 消耗：无<br> 射程：见下<br> 范围：见下<br> 描述：将双枪合并成一把大型枪炮，持续性的喷射能量，可以用高额伤害将前方大范围敌人直接轰杀。<br> 效果：<br> 你需要使用一个整轮动作进行蓄力，随后立刻执行两次普通枪械攻击，这两次攻击的射程提升至等同你的敏感范围，对范围内的所有敌方单位进行攻击，同时附带【即死】效果。<br> 若对方被攻击命中，则立刻死亡，这是一个A级创伤来源的即死效果。若对方没有因此死亡，则还需要用意志检定进行一次豁免，豁免难度等同伤害出目，豁免失败则进入【惊惧】状态，该状态持续一轮。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',24)])])}const h=e(o,[["render",s]]);export{R as __pageData,h as default};
